def main() -> None:
    OUT.mkdir(parents=True, exist_ok=True)
    keys = json.loads((Path(__file__).resolve().parents[1] / "data" / "bundled-translations" / "maps" / "ui-keys.json").read_text(encoding="utf-8"))
    for lang, vals in ("es", ES), ("fr", FR), ("ru", RU):
        if len(vals) != len(keys):
            raise SystemExit(f"{lang}: {len(vals)} != {len(keys)} keys")
        (OUT / f"{lang}-ui.json").write_text(json.dumps(vals, ensure_ascii=False, indent=2), encoding="utf-8")
        print(f"Wrote {lang}-ui.json ({len(vals)})")


if __name__ == "__main__":
    main()
